'use client';

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '@/components/auth-provider';
import Image from 'next/image';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Pencil, Save, X, Upload, User } from 'lucide-react';
import { toast } from 'sonner';

interface ProfileData {
  id: number;
  image_url: string | null;
  content: string | null;
  updated_at: string;
}

export function ProfileSection() {
  const { hasPermission } = useAuth();

  const [profile, setProfile] = useState<ProfileData | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editContent, setEditContent] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const fetchProfile = useCallback(async () => {
    try {
      const res = await fetch('/api/profile');
      if (res.ok) {
        const data = await res.json();
        setProfile({
          ...data,
          image_url: data.imageUrl || data.image_url,
        });
        setEditContent(data.content || '');
      }
    } catch (error) {
      console.error('Failed to fetch profile:', error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchProfile();
  }, [fetchProfile]);

  

  

  const handleSave = async () => {
    setIsSaving(true);
    try {
      const res = await fetch('/api/profile', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: editContent }),
      });

      if (res.ok) {
        await fetchProfile();
        setIsEditing(false);
        toast.success('프로필이 저장되었습니다.');
      } else {
        toast.error('저장에 실패했습니다.');
      }
    } catch {
      toast.error('저장 중 오류가 발생했습니다.');
    } finally {
      setIsSaving(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('image', file);

    try {
      const res = await fetch('/api/profile/image', {
        method: 'POST',
        body: formData,
      });

      if (res.ok) {
        await fetchProfile();
        toast.success('프로필 이미지가 업로드되었습니다.');
      } else {
        toast.error('이미지 업로드에 실패했습니다.');
      }
    } catch {
      toast.error('이미지 업로드 중 오류가 발생했습니다.');
    }
  };

  if (isLoading) {
    return (
      <Card className="w-full border-0 shadow-none bg-card/70 backdrop-blur-sm">
        <CardContent className="p-8">
          <div className="animate-pulse flex flex-col md:flex-row gap-8">
            <div className="w-32 md:w-48 h-32 md:h-48 bg-muted"></div>
            <div className="flex-1 space-y-4">
              <div className="h-4 bg-muted w-3/4"></div>
              <div className="h-4 bg-muted w-1/2"></div>
              <div className="h-4 bg-muted w-2/3"></div>
            </div>
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <>
      <Card className="w-full border-0 shadow-none bg-card/70 backdrop-blur-sm">
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle className="text-2xl font-semibold">Profile</CardTitle>
          {!isEditing && hasPermission(['SUPER_ADMIN']) && (
            <Button
              variant="outline"
              size="sm"
              onClick={() => setIsEditing(true)}
              className="flex items-center gap-2"
            >
              <Pencil className="h-4 w-4" />
              편집
            </Button>
          )}
        </CardHeader>
        <CardContent>
          <div className="flex flex-col md:flex-row gap-8">
            {/* Profile Image */}
            <div className="flex-shrink-0">
              <div className="relative w-32 h-32 md:w-48 md:h-48 border border-border bg-muted overflow-hidden">
                {profile?.image_url ? (
                  <Image
                    src={profile.image_url}
                    alt="Profile"
                    fill
                    className="object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <User className="h-16 w-16 text-muted-foreground" />
                  </div>
                )}
              </div>
              {isEditing && (
                <label className="mt-2 flex items-center justify-center gap-2 w-full py-2 px-4 bg-secondary text-secondary-foreground cursor-pointer hover:bg-primary hover:text-primary-foreground transition-colors">
                  <Upload className="h-4 w-4" />
                  이미지 업로드
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleImageUpload}
                    className="hidden"
                  />
                </label>
              )}
            </div>

            {/* Profile Content */}
            <div className="flex-1">
              {isEditing ? (
                <div className="space-y-4">
                  <Textarea
                    value={editContent}
                    onChange={(e) => setEditContent(e.target.value)}
                    placeholder="프로필 내용을 입력하세요..."
                    className="min-h-[200px] resize-none"
                  />
                  <div className="flex gap-2">
                    <Button
                      onClick={handleSave}
                      disabled={isSaving}
                      className="flex items-center gap-2"
                    >
                      <Save className="h-4 w-4" />
                      {isSaving ? '저장 중...' : '저장'}
                    </Button>
                    <Button
                      variant="outline"
                      onClick={() => {
                        setIsEditing(false);
                        setEditContent(profile?.content || '');
                      }}
                      className="flex items-center gap-2"
                    >
                      <X className="h-4 w-4" />
                      취소
                    </Button>
                  </div>
                </div>
              ) : (
                <div className="prose prose-sm max-w-none">
                  <p className="whitespace-pre-wrap text-foreground leading-relaxed">
                    {profile?.content || '프로필 내용이 없습니다. 편집 버튼을 눌러 내용을 추가하세요.'}
                  </p>
                </div>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      
    </>
  );
}
